load('exp2_lab2.mat')

% Voltage across Diode-Connected Transistor vs Input Voltage (all three)
figure(); %[output:039fbdfb]
semilogy(V_in_120, V_q_120, '.', DisplayName='120 \Omega') %[output:039fbdfb]
hold on; %[output:039fbdfb]
semilogy(V_in_10k, V_q_10k, '.', DisplayName='10 k\Omega') %[output:039fbdfb]
semilogy(V_in_200k, V_q_200k, '.', DisplayName='200 k\Omega') %[output:039fbdfb]
title('Voltage Across Transistor vs. Input Voltage') %[output:039fbdfb]
xlabel('V_{in} (V)') %[output:039fbdfb]
ylabel('V_{Q} (V)') %[output:039fbdfb]
legend(Location="best") %[output:039fbdfb]

% Current Flowing into Circuit vs. Input Voltage
figure(); %[output:776f6948]
semilogy(V_in_120, I_in_120, '.', DisplayName='120 \Omega') %[output:776f6948]
hold on; %[output:776f6948]
semilogy(V_in_10k, I_in_10k, '.', DisplayName='10 k\Omega') %[output:776f6948]
semilogy(V_in_200k, I_in_200k, '.', DisplayName='200 k\Omega') %[output:776f6948]
title('Current vs. Input Voltage of Circuit') %[output:776f6948]
xlabel('V_{in} (V)') %[output:776f6948]
ylabel('I_{in} (A)') %[output:776f6948]
legend(Location="best") %[output:776f6948]

% Plot showing input current vs applied input voltage (3 plots)
figure(); %[output:6bcbdb03]
plot(V_in_120, I_in_120, '.') %[output:6bcbdb03]
title('Circuit with 120 \Omega Resistor IV Plot') %[output:6bcbdb03]
xlabel('V_{in} (V)') %[output:6bcbdb03]
ylabel('I_{in} (A)') %[output:6bcbdb03]

figure(); %[output:7def44d3]
plot(V_in_10k, I_in_10k, '.') %[output:7def44d3]
title('Circuit with 10 k\Omega Resistor IV Plot') %[output:7def44d3]
xlabel('V_{in} (V)') %[output:7def44d3]
ylabel('I_{in} (A)') %[output:7def44d3]

figure(); %[output:385cabe0]
plot(V_in_200k, I_in_200k, '.') %[output:385cabe0]
title('Circuit with 200 k\Omega Resistor IV Plot') %[output:385cabe0]
xlabel('V_{in} (V)') %[output:385cabe0]
ylabel('I_{in} (A)') %[output:385cabe0] %[output:51b37dd6]

